export type LiveCell = [number, number];

export function nextGeneration(liveCells: LiveCell[]): LiveCell[] {
  const key = (x: number, y: number) => `${x},${y}`;
  const liveSet = new Set(liveCells.map(([x, y]) => key(x, y)));

  const result: LiveCell[] = [];
  for (const [x, y] of liveCells) {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveSet.has(key(x + dx, y + dy))) count++;
      }
    }
    if (count === 2 || count === 3) result.push([x, y]);
  }
  return result;
}

